script.text:
      &OutlineEntry;

function loadForm$&controller;$Dir(f) {
  if (f._action == 'Edit') setItem$&controller;$Disable(f, 'ma_so', true);
  if (f._action == 'New') setItem$&controller;$Disable(f, 'ma_so', false);
  if (f._action != 'View') onChange$&controller;$CalculateType(f);
}
function onChange$&controller;$Item(o) {
  var f = o.parentForm, name = o.field.Name;
  switch (name) {
    case 'ma_so':  
      if (f.getItem('ma_so_in').value == '') f.getItem('ma_so_in').value = o.value.toUpperCase();
      break;
    case 'kind':
      onChange$&controller;$CalculateType(f, true);
      break;
    case 'nguon_dl':
      var l = f.getItem('nguon_dl').value;
      setItem$&controller;$AllowNulls(f, 'ds_chi_tieu', ((l == 7)||(l == 8)));
      setItem$&controller;$FieldsEmpty(f, 'ds_chi_tieu', ((l == 7)||(l == 8)));
      setItem$&controller;$Disable(f, 'ds_chi_tieu', !((l == 7)||(l == 8)));
      break;
    default:
      break;
  }
}
function onChange$&controller;$CalculateType(f, force) {window.setTimeout(String.format('onFocus$&controller;$CalculateType(\'{0}\', {1});', f._id, force ? 1 : 0), 2);}
function onFocus$&controller;$CalculateType(id, force) {
  var f = $find(id), v = f.getItem('kind').value, t1 = f.getItem('thu_chi'), t2 = f.getItem('cach_tinh');
  switch (v) {
    case '0':
      setItem$&controller;$AllowNulls(f, 'ds_tk, ds_chi_tieu', false);
      setItem$&controller;$FieldsEmpty(f, 'ds_tk, ds_chi_tieu', false);
      setItem$&controller;$Disable(f, 'thu_chi, nguon_dl, ds_tk, ds_chi_tieu', true);
      setItem$&controller;$Disable(f, 'cach_tinh', false);
      setItem$&controller;$Live(t1, t2, false);
      break;
    case '1':
      setItem$&controller;$AllowNulls(f, 'ds_tk', true);
      setItem$&controller;$AllowNulls(f, 'ds_chi_tieu', false);
      setItem$&controller;$FieldsEmpty(f, 'ds_tk', true);
      setItem$&controller;$FieldsEmpty(f, 'cach_tinh, ds_chi_tieu', false);
      setItem$&controller;$Disable(f, 'ds_tk', false);
      setItem$&controller;$Disable(f, 'nguon_dl, ds_chi_tieu', true);
      setItem$&controller;$Live(t1, t2, true);
      break;
    case '2':
      setItem$&controller;$AllowNulls(f, 'ds_tk', false);
      setItem$&controller;$FieldsEmpty(f, 'cach_tinh, ds_tk', false);
      setItem$&controller;$Disable(f, 'cach_tinh, ds_tk', true);
      setItem$&controller;$Disable(f, 'nguon_dl', false);
      onChange$&controller;$Item(f.getItem('nguon_dl'));
      setItem$&controller;$Live(t1, t2, true);
      break;      
    default:
      break;
  }
}
function setItem$&controller;$AllowNulls(f, c, v) {
  var a = c.split(','), o, grandNode;
  for (var i = 0; i < a.length; i++) {
    o = f.getItem($func.trim(a[i])), grandNode = o.parentNode.parentNode;
    if (!v) {
      o.field.AllowNulls = true;
      Sys.UI.DomElement.removeCssClass(grandNode, 'Required');
    } else {
      o.field.AllowNulls = false;
      Sys.UI.DomElement.addCssClass(grandNode, 'Required');
      Sys.UI.DomElement.addCssClass(grandNode, f._id);
    }
  }
}
function setItem$&controller;$Disable(f, c, v) {
  var a = c.split(',');
  for (var i = 0; i < a.length; i++) {
    var o = f.getItem($func.trim(a[i]));
    if (o.a) $common.setVisible(o.a, !v);
    o.disabled = v;
  }
}
function setItem$&controller;$FieldsEmpty(f, c, v){
  var a = c.split(',');
  for (var i = 0; i < a.length; i++) {
    var o = f.getItem($func.trim(a[i]));
    if(!v) o.value = '';
  }
}
function setItem$&controller;$Live(t1, t2, type) {
  if (type) {if (t2.live) {t1.disabled = false; t1.focus();}}
    else {if (t1.live) {t2.disabled = false; t2.focus();}}
}

      &ScriptIrregular;
